from fastapi.responses import HTMLResponse


def dashboard() -> HTMLResponse:
    return HTMLResponse(
        """<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width'><title>Stock Hunter</title><style>body{font-family:system-ui;margin:0;background:#0b1020;color:#eef2ff}main{max-width:1100px;margin:auto;padding:24px}header{display:flex;justify-content:space-between;align-items:center}.card{background:#151c31;border:1px solid #29324f;border-radius:14px;padding:18px;margin:12px 0}.prime{border-color:#34d399}small{color:#9ca3af}.state{color:#34d399}button{background:#334155;color:white;border:0;border-radius:8px;padding:9px}body.light{background:#f8fafc;color:#111827}body.light .card{background:white;border-color:#d1d5db}</style></head><body><main><header><div><h1>Stock Hunter</h1><small>Best opportunities now — not a prediction</small></div><button onclick='document.body.classList.toggle("light")'>Theme</button></header><div id='status'>Loading…</div><section id='cards'></section></main><script>async function load(){try{const r=await fetch('/api/v1/opportunities?limit=5');const items=await r.json();document.getElementById('status').textContent=items.length?`${items.length} opportunities ranked`:'No qualified opportunity now';document.getElementById('cards').innerHTML=items.map((x,i)=>`<article class="card ${x.state==='prime_candidate'?'prime':''}"><h2>#${i+1} ${x.symbol}</h2><b class="state">${x.state.replaceAll('_',' ')}</b><p>${x.reasons.slice(0,3).join('<br>')}</p><p><b>What next:</b> ${x.what_next}</p><p><b>Invalidation:</b> ${x.invalidation}</p><small>Updated ${new Date(x.updated_at).toLocaleTimeString()}</small></article>`).join('')}catch(e){document.getElementById('status').textContent='System unavailable'}}</script><script>load();setInterval(load,10000)</script></body></html>"""  # noqa: E501
    )
